def evaluate_loan(credit, income, debt, emp):
    reasons = []
    if credit < 600: reasons.append("Low credit")
    if income < 25000: reasons.append("Low income")
    if debt > 0.43: reasons.append("High DTI")
    if not emp: reasons.append("Unemployed")
    if not reasons: return (True, "Approved")
    return (False, f"Denied: {'; '.join(reasons)}")
